import { MongoClient } from 'mongodb';
import 'dotenv/config';

const uri = process.env.MONGODB_URI;
if (!uri) {
	console.error('MONGODB_URI not set in .env');
	process.exit(1);
}

const client = new MongoClient(uri);

async function seed() {
	await client.connect();
	const db = client.db();

	// Clear existing data
	await db.collection('activities').deleteMany({});
	await db.collection('recipes').deleteMany({});
	await db.collection('meals').deleteMany({});

	// Seed activities (current week)
	const today = new Date();
	const monday = new Date(today);
	monday.setDate(today.getDate() - today.getDay() + 1);

	const activities = [
		{ title: 'Gym Session', type: 'gym', date: formatDate(monday, 0), color: '#ff6b35', duration: 60 },
		{ title: 'Recovery Yoga', type: 'recovery', date: formatDate(monday, 1), color: '#4caf50', duration: 45 },
		{ title: 'Cardio Run', type: 'cardio', date: formatDate(monday, 2), color: '#2196f3', duration: 30 },
		{ title: 'Rest Day', type: 'rest', date: formatDate(monday, 3), color: '#9e9e9e', duration: 0 },
		{ title: 'Gym Session', type: 'gym', date: formatDate(monday, 4), color: '#ff6b35', duration: 60 },
		{ title: 'Match Day', type: 'match', date: formatDate(monday, 5), color: '#e91e63', duration: 90 },
		{ title: 'Recovery', type: 'recovery', date: formatDate(monday, 6), color: '#4caf50', duration: 30 }
	];

	await db.collection('activities').insertMany(activities);

	// Seed recipes
	const recipes = [
		{
			title: 'Ginger Shot',
			description: 'Immune-boosting ginger shot to kickstart your morning.',
			ingredients: ['Fresh ginger (50g)', 'Lemon juice (1 lemon)', 'Honey (1 tsp)', 'Cayenne pepper (pinch)'],
			steps: ['Peel and chop ginger', 'Blend with lemon juice and water', 'Strain through fine mesh', 'Add honey and cayenne'],
			category: 'snack',
			prepTime: 10,
			calories: 35,
			image: ''
		},
		{
			title: 'Protein Oatmeal',
			description: 'High-protein oatmeal with berries for sustained energy.',
			ingredients: ['Oats (80g)', 'Protein powder (30g)', 'Banana (1)', 'Mixed berries (100g)', 'Almond milk (200ml)'],
			steps: ['Cook oats with almond milk', 'Stir in protein powder', 'Top with sliced banana and berries'],
			category: 'breakfast',
			prepTime: 15,
			calories: 450,
			image: ''
		},
		{
			title: 'Chicken & Rice Bowl',
			description: 'Classic post-workout meal with lean protein and carbs.',
			ingredients: ['Chicken breast (200g)', 'Brown rice (150g)', 'Broccoli (100g)', 'Soy sauce (1 tbsp)', 'Sesame oil (1 tsp)'],
			steps: ['Cook rice according to package', 'Grill chicken breast', 'Steam broccoli', 'Assemble bowl and drizzle with soy sauce and sesame oil'],
			category: 'lunch',
			prepTime: 30,
			calories: 650,
			image: ''
		}
	];

	const insertedRecipes = await db.collection('recipes').insertMany(recipes);
	const recipeIds = Object.values(insertedRecipes.insertedIds);

	// Seed meals for today
	const todayStr = today.toISOString().split('T')[0];
	const meals = [
		{ recipeId: recipeIds[1], date: todayStr, mealType: 'breakfast', title: 'Protein Oatmeal', image: '' },
		{ recipeId: recipeIds[2], date: todayStr, mealType: 'lunch', title: 'Chicken & Rice Bowl', image: '' },
		{ recipeId: recipeIds[0], date: todayStr, mealType: 'snack', title: 'Ginger Shot', image: '' }
	];

	await db.collection('meals').insertMany(meals);

	console.log('✅ Database seeded successfully!');
	console.log(`   - ${activities.length} activities`);
	console.log(`   - ${recipes.length} recipes`);
	console.log(`   - ${meals.length} meals`);

	await client.close();
}

function formatDate(monday: Date, offsetDays: number): string {
	const d = new Date(monday);
	d.setDate(d.getDate() + offsetDays);
	return d.toISOString().split('T')[0];
}

seed().catch(console.error);

import os

plan_server = """import type { PageServerLoad, Actions } from './$types';
import db from '$lib/server/db';
import type { Activity } from '$lib/types';
import { ObjectId } from 'mongodb';
import { fail } from '@sveltejs/kit';

export const load: PageServerLoad = async () => {
	const today = new Date();
	const monday = new Date(today);
	monday.setDate(today.getDate() - ((today.getDay() + 6) % 7));
	const sunday = new Date(monday);
	sunday.setDate(monday.getDate() + 6);

	const startDate = monday.toISOString().split('T')[0];
	const endDate = sunday.toISOString().split('T')[0];

	const activities = await db.collection<Activity>('activities')
		.find({ date: { $gte: startDate, $lte: endDate } })
		.sort({ date: 1 })
		.toArray();

	const weekDays = [];
	for (let i = 0; i < 7; i++) {
		const d = new Date(monday);
		d.setDate(monday.getDate() + i);
		const dateStr = d.toISOString().split('T')[0];
		weekDays.push({
			date: dateStr,
			label: d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }),
			activities: JSON.parse(JSON.stringify(activities.filter(a => a.date === dateStr)))
		});
	}

	return { weekDays };
};

const colorMap: Record<string, string> = {
	gym: '#ff6b35',
	match: '#e91e63',
	recovery: '#4caf50',
	rest: '#9e9e9e',
	cardio: '#2196f3'
};

export const actions: Actions = {
	create: async ({ request }) => {
		const formData = await request.formData();
		const title = formData.get('title') as string;
		const type = formData.get('type') as string;
		const date = formData.get('date') as string;
		const duration = Number(formData.get('duration') || 0);
		const notes = (formData.get('notes') as string) || '';

		if (!title || !type || !date) {
			return fail(400, { error: 'Title, type, and date are required.' });
		}

		await db.collection('activities').insertOne({
			title, type, date, duration, notes,
			color: colorMap[type] || '#ff6b35'
		});

		return { success: true };
	},

	update: async ({ request }) => {
		const formData = await request.formData();
		const id = formData.get('id') as string;
		const title = formData.get('title') as string;
		const type = formData.get('type') as string;
		const date = formData.get('date') as string;
		const duration = Number(formData.get('duration') || 0);
		const notes = (formData.get('notes') as string) || '';

		if (!id || !title || !type || !date) {
			return fail(400, { error: 'Missing required fields.' });
		}

		await db.collection('activities').updateOne(
			{ _id: new ObjectId(id) },
			{ $set: { title, type, date, duration, notes, color: colorMap[type] || '#ff6b35' } }
		);

		return { success: true };
	},

	delete: async ({ request }) => {
		const formData = await request.formData();
		const id = formData.get('id') as string;

		if (!id) return fail(400, { error: 'ID required.' });

		await db.collection('activities').deleteOne({ _id: new ObjectId(id) });
		return { success: true };
	}
};
"""

plan_page = """<script lang="ts">
	import { enhance } from '$app/forms';

	let { data, form } = $props();
	let showForm = $state(false);
	let editingId = $state<string | null>(null);

	const activityTypes = ['gym', 'match', 'recovery', 'rest', 'cardio'];
</script>

<section class="plan-page">
	<div class="plan-header">
		<h1>Weekly Plan</h1>
		<button class="btn-primary" onclick={() => showForm = !showForm}>
			{showForm ? 'Cancel' : '+ Add Activity'}
		</button>
	</div>

	{#if form?.error}
		<div class="error-msg">{form.error}</div>
	{/if}
	{#if form?.success}
		<div class="success-msg">Activity saved successfully!</div>
	{/if}

	{#if showForm}
		<form method="POST" action="?/create" use:enhance class="card activity-form">
			<h3>New Activity</h3>
			<div class="form-grid">
				<label>
					Title
					<input name="title" type="text" required placeholder="e.g. Gym Session" />
				</label>
				<label>
					Type
					<select name="type" required>
						{#each activityTypes as t}
							<option value={t}>{t.charAt(0).toUpperCase() + t.slice(1)}</option>
						{/each}
					</select>
				</label>
				<label>
					Date
					<input name="date" type="date" required />
				</label>
				<label>
					Duration (min)
					<input name="duration" type="number" min="0" value="60" />
				</label>
			</div>
			<label>
				Notes
				<textarea name="notes" rows="2" placeholder="Optional notes..."></textarea>
			</label>
			<button type="submit" class="btn-primary">Create Activity</button>
		</form>
	{/if}

	<div class="week-grid">
		{#each data.weekDays as day}
			<div class="day-column">
				<div class="day-label">{day.label}</div>
				{#each day.activities as activity}
					<div class="activity-tag" style="background: {activity.color}20; border-left: 3px solid {activity.color};">
						{#if editingId === activity._id}
							<form method="POST" action="?/update" use:enhance>
								<input type="hidden" name="id" value={activity._id} />
								<input name="title" value={activity.title} required />
								<select name="type">
									{#each activityTypes as t}
										<option value={t} selected={t === activity.type}>{t}</option>
									{/each}
								</select>
								<input name="date" type="date" value={activity.date} required />
								<input name="duration" type="number" value={activity.duration} />
								<textarea name="notes">{activity.notes || ''}</textarea>
								<div class="edit-actions">
									<button type="submit" class="btn-primary">Save</button>
									<button type="button" onclick={() => editingId = null}>Cancel</button>
								</div>
							</form>
						{:else}
							<div class="activity-content">
								<strong>{activity.title}</strong>
								{#if activity.duration}
									<span class="duration">{activity.duration} min</span>
								{/if}
							</div>
							<div class="activity-actions">
								<button onclick={() => editingId = activity._id} title="Edit">✏️</button>
								<form method="POST" action="?/delete" use:enhance style="display:inline;">
									<input type="hidden" name="id" value={activity._id} />
									<button type="submit" title="Delete">️</button>
								</form>
							</div>
						{/if}
					</div>
				{:else}
					<div class="no-activity">No activity</div>
				{/each}
			</div>
		{/each}
	</div>
</section>

<style>
	.plan-page { display: flex; flex-direction: column; gap: 1.5rem; }
	.plan-header { display: flex; justify-content: space-between; align-items: center; }
	.error-msg { background: #f4433620; color: #f44336; padding: 0.75rem; border-radius: 8px; }
	.success-msg { background: #4caf5020; color: #4caf50; padding: 0.75rem; border-radius: 8px; }
	.activity-form { display: flex; flex-direction: column; gap: 1rem; }
	.form-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 1rem; }
	.activity-form label { display: flex; flex-direction: column; gap: 0.25rem; font-size: 0.875rem; color: var(--color-text-muted); }
	.activity-form input, .activity-form select, .activity-form textarea {
		background: var(--color-bg); color: var(--color-text); border: 1px solid #333;
		border-radius: 6px; padding: 0.5rem; font-size: 0.875rem;
	}
	.week-grid { display: grid; grid-template-columns: repeat(7, 1fr); gap: 0.5rem; }
	.day-column { display: flex; flex-direction: column; gap: 0.5rem; }
	.day-label { font-size: 0.75rem; font-weight: 600; color: var(--color-text-muted); text-align: center; padding: 0.5rem; background: var(--color-surface); border-radius: 6px; }
	.activity-tag { padding: 0.5rem; border-radius: 6px; font-size: 0.8rem; }
	.activity-content { display: flex; flex-direction: column; gap: 0.25rem; }
	.duration { font-size: 0.7rem; color: var(--color-text-muted); }
	.activity-actions { display: flex; gap: 0.25rem; margin-top: 0.25rem; }
	.activity-actions button { background: none; padding: 0.2rem; font-size: 0.75rem; }
	.edit-actions { display: flex; gap: 0.5rem; margin-top: 0.5rem; }
	.no-activity { font-size: 0.75rem; color: var(--color-text-muted); text-align: center; padding: 1rem 0.5rem; }

	@media (max-width: 768px) {
		.week-grid { grid-template-columns: 1fr; }
	}
</style>
"""

os.makedirs('src/routes/plan', exist_ok=True)
with open('src/routes/plan/+page.server.ts', 'w') as f:
    f.write(plan_server)
with open('src/routes/plan/+page.svelte', 'w') as f:
    f.write(plan_page)

print("Done: Plan page files written.")

:root {
	--color-primary: #ff6b35;
	--color-bg: #0f0f23;
	--color-surface: #1a1a2e;
	--color-text: #e0e0e0;
	--color-text-muted: #888;
	--color-success: #4caf50;
	--color-danger: #f44336;
	--radius: 8px;
}

* {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

body {
	font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
	background: var(--color-bg);
	color: var(--color-text);
	min-height: 100vh;
}

main {
	max-width: 1200px;
	margin: 0 auto;
	padding: 2rem 1.5rem;
}

button {
	cursor: pointer;
	border: none;
	border-radius: var(--radius);
	padding: 0.5rem 1rem;
	font-size: 0.875rem;
	font-weight: 500;
}

.btn-primary {
	background: var(--color-primary);
	color: white;
}

.btn-primary:hover {
	opacity: 0.9;
}

.card {
	background: var(--color-surface);
	border-radius: var(--radius);
	padding: 1.5rem;
}

import { MongoClient } from 'mongodb';
import { MONGODB_URI } from '$env/static/private';

const client = new MongoClient(MONGODB_URI);

export async function startMongo() {
	await client.connect();
	return client.db();
}

const db = client.db();

export default db;

import type { ObjectId } from 'mongodb';

export interface Activity {
	_id?: ObjectId;
	title: string;
	type: 'gym' | 'match' | 'recovery' | 'rest' | 'cardio';
	date: string; // ISO date string YYYY-MM-DD
	time?: string;
	duration?: number; // minutes
	color: string;
	notes?: string;
}

export interface Recipe {
	_id?: ObjectId;
	title: string;
	description: string;
	image?: string;
	ingredients: string[];
	steps: string[];
	category: 'breakfast' | 'lunch' | 'dinner' | 'snack';
	prepTime: number; // minutes
	calories?: number;
}

export interface Meal {
	_id?: ObjectId;
	recipeId: ObjectId;
	date: string;
	mealType: 'breakfast' | 'lunch' | 'dinner' | 'snack';
	title: string;
	image?: string;
}

export interface MoodEntry {
	_id?: ObjectId;
	date: string;
	mood: 1 | 2 | 3 | 4 | 5;
	emoji: string;
	note?: string;
}

import type { PageServerLoad } from './$types';
import db from '$lib/server/db';
import type { Activity, Meal } from '$lib/types';

export const load: PageServerLoad = async () => {
	const today = new Date().toISOString().split('T')[0];

	const todayActivity = await db.collection<Activity>('activities').findOne({ date: today });
	const meals = await db.collection<Meal>('meals').find({ date: today }).toArray();

	// Dynamic header message
	let headerMessage = "Today it's a Rest Day";
	if (todayActivity) {
		switch (todayActivity.type) {
			case 'match': headerMessage = "Today it's Match Day "; break;
			case 'gym': headerMessage = "Today it's Gym Day "; break;
			case 'cardio': headerMessage = "Today it's Cardio Day "; break;
			case 'recovery': headerMessage = "Today it's Recovery Day "; break;
			default: headerMessage = "Today it's a Rest Day ";
		}
	}

	return {
		headerMessage,
		todayActivity: todayActivity ? JSON.parse(JSON.stringify(todayActivity)) : null,
		meals: JSON.parse(JSON.stringify(meals))
	};
};
